"use client";

import React from "react";
import * as Scrollytelling from "@bsmnt/scrollytelling";

type Intensity = "subtle" | "aggressive";

export interface KineticTextSplitProps {
  /** the headline to animate, one word at a time */
  text: string;
  intensity?: Intensity;
  className?: string;
  as?: "h1" | "h2" | "h3" | "p";
}

/*
 * A kinetic per-word scroll reveal built on @bsmnt/scrollytelling (declarative GSAP ScrollTrigger).
 * SAFETY IS BAKED IN, not left to the caller: prefers-reduced-motion and empty/one-word text both
 * degrade to plain static text, and all scroll timing (start/end percentages, stagger, from-state)
 * has sane defaults derived from the intensity prop. The agent supplies only the text (+ optional
 * intensity); a bad or missing prop can never produce a broken animation.
 */
export function KineticTextSplit({ text, intensity = "aggressive", className, as = "h1" }: KineticTextSplitProps) {
  const Tag = as;
  const words = String(text ?? "").trim().split(/\s+/).filter(Boolean);

  const reduced =
    typeof window !== "undefined" &&
    typeof window.matchMedia === "function" &&
    window.matchMedia("(prefers-reduced-motion: reduce)").matches;

  // Static fallback — reduced motion or nothing to split.
  if (reduced || words.length === 0) {
    return <Tag className={className}>{text}</Tag>;
  }

  const span = intensity === "aggressive" ? 55 : 40; // total scroll % the reveal occupies
  const step = words.length > 1 ? span / words.length : span;
  const from =
    intensity === "aggressive"
      ? { opacity: 0, yPercent: 120, rotate: 6 }
      : { opacity: 0, yPercent: 40 };

  return (
    <Scrollytelling.Root start="top 80%" end="bottom 55%">
      <Tag className={className} style={{ display: "flex", flexWrap: "wrap", gap: "0.25em" }}>
        {words.map((word, i) => {
          const start = Math.min(98, Math.round(i * step));
          const end = Math.min(100, Math.round(i * step + step * 1.6));
          return (
            <span key={i} style={{ display: "inline-block", overflow: "hidden", lineHeight: 1.1 }}>
              <Scrollytelling.Animation tween={{ start, end: end > start ? end : start + 1, from }}>
                <span style={{ display: "inline-block" }}>{word}</span>
              </Scrollytelling.Animation>
            </span>
          );
        })}
      </Tag>
    </Scrollytelling.Root>
  );
}

export default KineticTextSplit;

