import { KineticTextSplit } from './component'

// ONE headline with a per-word scroll reveal. Pass the headline text as the 'text' prop (a string).
// Timing + reduced-motion fallback are handled inside — you only choose the words and intensity.
export default function Section() {
  return (
    <section className="min-h-[70vh] flex items-center justify-center px-6 bg-background">
      <KineticTextSplit
        text="Your bold on-brief headline"
        intensity="aggressive"
        as="h1"
        className="text-foreground text-5xl md:text-7xl font-bold tracking-tight max-w-4xl"
      />
    </section>
  )
}
